import { newId } from "./id";

export interface Session {
  id: string;
  userId: string;
  createdAt: string; // ISO-8601
  expiresAt: string; // ISO-8601
}

const SESSION_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

/** Create a new session record for the given user. */
export function createSession(userId: string): Session {
  const now = Date.now();
  return {
    id: newId(),
    userId,
    createdAt: new Date(now).toISOString(),
    expiresAt: new Date(now + SESSION_TTL_MS).toISOString(),
  };
}
```

`id.ts` (신규 — `newId()` ULID 생성기, AGENTS.md 준수):
```ts
const ENCODING = "0123456789ABCDEFGHJKMNPQRSTVWXYZ"; // Crockford Base32
const ENCODING_LEN = ENCODING.length; // 32
const TIME_LEN = 10;
const RANDOM_LEN = 16;

function encodeTime(time: number): string {
  let str = "";
  for (let i = TIME_LEN - 1; i >= 0; i--) {
    const mod = time % ENCODING_LEN;
    str = ENCODING[mod] + str;
    time = (time - mod) / ENCODING_LEN;
  }
  return str;
}

function encodeRandom(): string {
  const bytes = new Uint8Array(RANDOM_LEN);
  crypto.getRandomValues(bytes); // CSPRNG — never Math.random (AGENTS.md)
  let str = "";
  for (let i = 0; i < RANDOM_LEN; i++) str += ENCODING[bytes[i] % ENCODING_LEN];
  return str;
}

/** Generate a new 26-character ULID for a fresh entity. */
export function newId(): string {
  return encodeTime(Date.now()) + encodeRandom();
}
```

